sinks.expression:
array_map(
				function ( $name ) {
					return new \WP_Http_Cookie( [
						'name' => wp_unslash( $name ),
						'value' => sanitize_text_field( wp_unslash( $_COOKIE[ $name ] ?? '' ) ),
					] );
				},
				array_keys( $_COOKIE )
			)

